# Allowlist of permitted redirect domains/hosts
ALLOWED_HOSTS = {
    'localhost',
    '127.0.0.1',
    'myapp.example.com',
    'www.myapp.example.com',
}

# Allowlist of safe internal path prefixes
ALLOWED_PATH_PREFIXES = (
    '/dashboard',
    '/profile',
    '/settings',
    '/home',
    '/account',
    '/projects',
    '/reports',
)

# Default safe redirect destination
DEFAULT_REDIRECT = '/dashboard'


def is_safe_redirect_url(target):
    """
    Validate that the redirect URL is safe and not an open redirect.
    
    A URL is considered safe if:
    1. It is a relative URL (no scheme/host) with an allowed path prefix, OR
    2. It is an absolute URL whose host is in the ALLOWED_HOSTS allowlist
       and uses http or https scheme, and has an allowed path prefix.
    3. It does not contain protocol-relative URLs (e.g., //evil.com).
    """
    if not target:
        return False

    # Strip whitespace
    target = target.strip()

    # Block empty or whitespace-only targets
    if not target:
        return False

    # Block protocol-relative URLs like //evil.com
    if target.startswith('//'):
        return False

    # Block URLs with backslashes (can be used to bypass parsing)
    if '\\' in target:
        return False

    # Block javascript:, data:, vbscript: and other dangerous schemes
    lower_target = target.lower().strip()
    dangerous_schemes = ('javascript:', 'data:', 'vbscript:', 'file:', 'ftp:')
    for scheme in dangerous_schemes:
        if lower_target.startswith(scheme):
            return False

    # Parse the target URL
    parsed = urlparse(target)

    # If there's a netloc (host), validate it against the allowlist
    if parsed.netloc:
        # Extract hostname (without port)
        hostname = parsed.hostname
        if hostname not in ALLOWED_HOSTS:
            return False
        # Only allow http and https schemes
        if parsed.scheme not in ('http', 'https'):
            return False
    elif parsed.scheme:
        # Has a scheme but no netloc — suspicious (e.g., javascript:alert(1))
        return False

    # Validate the path starts with an allowed prefix
    path = parsed.path
    if not path or path == '/':
        # Redirect to root is acceptable only if host is allowed
        if parsed.netloc:
            return parsed.hostname in ALLOWED_HOSTS
        return False

    # Normalize path to prevent traversal
    # Ensure path starts with /
    if not path.startswith('/'):
        return False

    # Check against allowed path prefixes
    path_is_allowed = any(path.startswith(prefix) for prefix in ALLOWED_PATH_PREFIXES)
    if not path_is_allowed:
        return False

    return True


def get_safe_redirect_url(target):
    """
    Return the target URL if it passes safety validation,
    otherwise return the default safe redirect.
    """
    if target and is_safe_redirect_url(target):
        return target
    return DEFAULT_REDIRECT


